class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j <= n; j++) {
                string t = s.substr(i, j - i);
                int count = 0;
                for (int k = 1; k < t.size(); k++) {
                    if (t[k] == t[k - 1]) {
                        count++;
                    }
                    if (count > 1) {
                        break;
                    }
                }
                if (count <= 1) {
                    res = max(res, (int)t.size());
                }
            }
        }
        return res;
    }
};

